                stopwatch.Stop();
                // Write metadata to console
            }
            catch (Exception ex) {
                // Write exception to console
            }
            return stopwatch.Elapsed;
        });
    }
    for (int i = 0; i < iterations; i++) {
        tasks[i].Start();
    }
    Task.WaitAll(tasks);
}
{code}


However the following code works:

{code:csharp}
