   var stopwatch = new Stopwatch();
   stopwatch.Start();
   try {
       var metadataCollection = database.GetCollection<CacheMetadata>(METADATA_COLLECTION_NAME);
       CacheMetadata metadata = await metadataCollection
           .Find(m => m.IntegrationId == _integrationId)
